226	    pub(crate) async fn next_data_packets(&self) -> Result<Option<(Vec<UdtDataPacket>, Instant)>> {
227	        if !self.status().is_alive() {
228	            if *UDT_DEBUG {
229	                eprintln!(
230	                    "No data to send: socket {} has status {:?}",
231	                    self.socket_id,
232	                    self.status()
233	                );
234	            };
235	            return Ok(None);
236	        }
237	        let now = Instant::now();
238	        let mut probe = false;
239	
240	        let to_resend = {
241	            let mut state = self.state();
242	            let data_delay = now - state.next_data_target_time;
243	
244	            if !data_delay.is_zero() {
245	                state.interpacket_time_diff += data_delay;
246	            }
247	
248	            let last_data_ack_processed = state.last_data_ack_processed;
249	            state
250	                .snd_loss_list
251	                .pop_after(last_data_ack_processed)
252	                .map(|seq| (seq, seq - last_data_ack_processed))
253	        };
254	
255	        let packets = match to_resend {
256	            Some((seq, offset)) => {
257	                // Loss retransmission has priority
258	                if offset < 0 {
259	                    if *UDT_DEBUG {
260	                        eprintln!("unexpected offset {} in sender loss list", offset);
261	                    }
262	                    return Ok(None);
263	                }
264	                let to_send = self.snd_buffer.lock().unwrap().read_data(
265	                    offset as usize,
266	                    seq,
267	                    self.peer_socket_id().unwrap(),
268	                    self.start_time,
269	                );
270	                match to_send {
271	                    Err((msg_number, msg_len)) => {
272	                        if msg_len == 0 {
273	                            return Ok(None);
274	                        }
275	                        let (start, end) = (seq, seq + msg_len as i32 - 1);
276	                        let drop = UdtControlPacket::new_drop(
277	                            msg_number,
278	                            start,
279	                            end,
280	                            self.peer_socket_id().unwrap(),
281	                        );
282	                        self.send_packet(drop.into()).await?;
283	
284	                        let mut state = self.state();
285	                        let last_data_ack_processed = state.last_data_ack_processed;
286	                        state.snd_loss_list.remove_all(last_data_ack_processed, end);
287	                        if (end + 1) - state.curr_snd_seq_number > 0 {
288	                            state.curr_snd_seq_number = end + 1;
289	                        }
290	                        return Ok(None);
291	                    }
292	                    Ok(packet) => vec![packet],
293	                }
294	            }
295	            None => {
296	                let congestion_window_size = self
297	                    .rate_control
298	                    .read()
299	                    .unwrap()
300	                    .get_congestion_window_size();
301	                let window_size = std::cmp::min(
302	                    self.flow.read().unwrap().flow_window_size,
303	                    congestion_window_size,
304	                );
305	                let mut state = self.state();
306	                if (state.curr_snd_seq_number - state.last_ack_received) > window_size as i32 {
307	                    state.next_data_target_time = now;
308	                    state.interpacket_time_diff = Duration::ZERO;
309	                    return Ok(None);
310	                }
311	                match self.snd_buffer.lock().unwrap().fetch_batch(
312	                    state.curr_snd_seq_number + 1,
313	                    self.peer_socket_id().unwrap(),
314	                    self.start_time,
315	                ) {
316	                    packets if !packets.is_empty() => {
317	                        let new_snd_seq_number = state.curr_snd_seq_number + packets.len() as i32;
318	                        state.curr_snd_seq_number = new_snd_seq_number;
319	                        self.rate_control
320	                            .write()
321	                            .unwrap()
322	                            .set_curr_snd_seq_number(new_snd_seq_number);
323	                        if state.curr_snd_seq_number.number() % 16 == 0 {
324	                            probe = true;
325	                        }
326	                        packets
327	                    }
328	                    _ => {
329	                        state.next_data_target_time = now;
330	                        state.interpacket_time_diff = Duration::ZERO;
331	                        return Ok(None);
332	                    }
333	                }
334	            }
335	        };
336	
337	        // update stats
338	        if probe {
339	            return Ok(Some((packets, now)));
340	        }
341	
342	        let mut state = self.state();
343	        let interval = state.interpacket_interval * packets.len() as u32;
344	        let target_time = if state.interpacket_time_diff >= interval {
345	            state.interpacket_time_diff -= interval;
346	            now
347	        } else {
348	            let target = now + interval - state.interpacket_time_diff;
349	            state.interpacket_time_diff = Duration::ZERO;
350	            target
351	        };
352	
353	        Ok(Some((packets, target_time)))
354	    }
355	
356	    fn compute_cookie(&self, addr: &SocketAddr, offset: Option<isize>) -> u32 {
357	        let timestamp = (self.start_time.elapsed().as_secs() / 60) + offset.unwrap_or(0) as u64; // secret changes every one minute
358	        let host = addr.ip();
359	        let port = addr.port();
360	        let salt: &str = &(*SALT);
361	        u32::from_be_bytes(
362	            Sha256::digest(format!("{salt}:{host}:{port}:{timestamp}").as_bytes())[..4]
363	                .try_into()
364	                .unwrap(),
365	        )
366	    }
367	
368	    pub(crate) async fn send_to(&self, addr: &SocketAddr, packet: UdtPacket) -> Result<()> {
369	        self.multiplexer()
370	            .expect("multiplexer not initialized")
371	            .send_to(addr, packet)
372	            .await?;
373	        Ok(())
374	    }
375	
376	    pub(crate) async fn listen_on_handshake(
377	        &self,
378	        addr: SocketAddr,
379	        hs: &HandShakeInfo,
380	    ) -> Result<()> {
381	        if !self.status().is_alive() {
382	            return Err(Error::new(ErrorKind::ConnectionRefused, "socket closed"));
383	        }
384	
385	        if hs.connection_type == 1 {
386	            // Regular connection, respond to handshake
387	            let mut hs_response = hs.clone();
388	            let dest_socket_id = hs_response.socket_id;
389	            hs_response.syn_cookie = self.compute_cookie(&addr, None);
390	            let hs_packet = UdtControlPacket::new_handshake(hs_response, dest_socket_id);
391	            self.send_to(&addr, hs_packet.into()).await?;
392	            return Ok(());
393	        }
394	
395	        if hs.connection_type != -1 {
396	            return Err(Error::new(
397	                ErrorKind::InvalidData,
398	                format!("invalid connection_type: {}", hs.connection_type),
399	            ));
400	        }
401	
402	        // Validate client response
403	        let syn_cookie = hs.syn_cookie;
404	        if syn_cookie != self.compute_cookie(&addr, None)
405	            && syn_cookie != self.compute_cookie(&addr, Some(-1))
406	        {
407	            // Invalid cookie;
408	            return Err(Error::new(ErrorKind::PermissionDenied, "invalid cookie"));
409	        }
410	
411	        let dest_socket_id = hs.socket_id;
412	        let udt_version = self.configuration.read().unwrap().udt_version();
413	        if hs.udt_version != udt_version || hs.socket_type != self.socket_type {
414	            // Reject request
415	            let mut hs_response = hs.clone();
416	            hs_response.connection_type = 1002; // Error codes defined in C++ implementation
417	            let hs_packet = UdtControlPacket::new_handshake(hs_response, dest_socket_id);
418	            self.send_to(&addr, hs_packet.into()).await?;
419	            return Err(Error::new(
420	                ErrorKind::ConnectionRefused,
421	                "configuration mismatch",
422	            ));
423	        }
424	
425	        Udt::get()
426	            .write()
427	            .await
428	            .new_connection(self, addr, hs)
429	            .await?;
430	        // Send handshake packet in case of errors on connection?
431	
432	        Ok(())
433	    }
