232	        [
233	            self.udt_version,
234	            self.socket_type as u32,
235	            self.initial_seq_number.number(),
236	            self.max_packet_size,
237	            self.max_window_size,
238	        ]
239	        .iter()
240	        .flat_map(|v| v.to_be_bytes())
241	        .chain(self.connection_type.to_be_bytes().into_iter())
242	        .chain(self.socket_id.to_be_bytes().into_iter())
243	        .chain(self.syn_cookie.to_be_bytes().into_iter())
244	        .chain(ip_to_bytes(self.ip_address))
245	        .collect()
246	    }
