249	        let get_u32 =
250	            |idx: usize| u32::from_be_bytes(raw[(idx * 4)..(idx + 1) * 4].try_into().unwrap());
251	        let addr: IpAddr = {
252	            if raw[36..48].iter().all(|b| *b == 0) {
253	                // IPv4
254	                let octets: [u8; 4] = raw[32..36].try_into().unwrap();
255	                octets.into()
256	            } else {
257	                // IPv6
258	                let octets: [u8; 16] = raw[32..48].try_into().unwrap();
259	                octets.into()
260	            }
261	        };
262	
263	        Ok(Self {
264	            udt_version: get_u32(0),
265	            socket_type: get_u32(1).try_into()?,
266	            initial_seq_number: get_u32(2).into(),
267	            max_packet_size: get_u32(3),
268	            max_window_size: get_u32(4),
269	            connection_type: i32::from_be_bytes(raw[20..24].try_into().unwrap()),
270	            socket_id: get_u32(6),
271	            syn_cookie: get_u32(7),
272	            ip_address: addr,
273	        })
274	    }
